package scanner

import (
	"context"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/google/uuid"
	"github.com/navidrome/navidrome/core/artwork"
	"github.com/navidrome/navidrome/log"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/tests"
)

// TestFullScanOfFixtureDirectory tests the complete scan pipeline with real audio files
func TestFullScanOfFixtureDirectory(t *testing.T) {
	ctx := context.Background()

	// Create mock repositories
	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     genreRepo,
	}

	// Create scanner with mock datastore and empty playlists/cacheWarmer
	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	// Create a test library pointing to the fixtures directory
	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{}, // First scan
	}

	// Run the scan
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// Verify that changes were detected
	if changeCount == 0 {
		t.Errorf("Expected changes to be detected, but got changeCount=0")
	}

	// Verify that media files were added to the database
	allFiles, err := mfRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get all media files: %v", err)
	}

	if len(allFiles) == 0 {
		t.Fatal("Expected media files to be added to the database, but got none")
	}

	// Verify that at least one file has expected metadata
	hasValidFile := false
	for _, mf := range allFiles {
		// Test files should have basic metadata extracted
		if mf.Title != "" && mf.Path != "" {
			hasValidFile = true
			// Verify that the path is correctly set
			if !filepath.IsAbs(mf.Path) && mf.Path != "" {
				// Path should be relative to library root or absolute
				_, err := os.Stat(mf.Path)
				if err == nil || os.IsNotExist(err) {
					// File can be missing in fixtures but path should be valid format
					t.Logf("Found media file: %s (%s)", mf.Title, mf.Path)
				}
			}
			break
		}
	}

	if !hasValidFile {
		t.Errorf("Expected at least one media file with valid title and path, got: %+v", allFiles)
	}
}

// TestMetadataExtraction tests that metadata is correctly extracted from audio files
func TestMetadataExtraction(t *testing.T) {
	ctx := context.Background()

	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	allFiles, _ := mfRepo.GetAll()

	// Verify essential metadata fields are populated
	for _, mf := range allFiles {
		// Title should be set (either from tags or filename)
		if mf.Title == "" {
			t.Errorf("Media file has empty title: %s", mf.Path)
		}

		// Suffix should be extracted from file extension
		if mf.Suffix == "" {
			t.Errorf("Media file has empty suffix: %s", mf.Path)
		}

		// Library ID should be set correctly
		if mf.LibraryID != lib.ID {
			t.Errorf("Media file has wrong LibraryID: expected %d, got %d", lib.ID, mf.LibraryID)
		}

		// Timestamps should be set
		if mf.UpdatedAt.IsZero() {
			t.Errorf("Media file has zero UpdatedAt: %s", mf.Path)
		}
	}
}

// TestAlbumAndArtistCreation tests that album and artist records are created during scan
func TestAlbumAndArtistCreation(t *testing.T) {
	ctx := context.Background()

	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// Get all albums and artists created during scan
	albums, err := albumRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get albums: %v", err)
	}

	// Note: Albums may be empty if test files don't have proper album metadata
	// But we should be able to retrieve them without error
	t.Logf("Created %d albums during scan", len(albums))

	// Verify that any created albums have proper structure
	for _, album := range albums {
		if album.ID == "" {
			t.Error("Album has empty ID")
		}
		if album.LibraryID != lib.ID {
			t.Errorf("Album has wrong LibraryID: expected %d, got %d", lib.ID, album.LibraryID)
		}
	}
}

// TestIncrementalScanWithNoChanges verifies that re-scanning without file changes produces no DB updates
func TestIncrementalScanWithNoChanges(t *testing.T) {
	ctx := context.Background()

	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{}, // First scan
	}

	// First scan
	progress := make(chan uint32, 100)
	changeCount1, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("First scan failed: %v", err)
	}

	// Get the count of files from first scan
	filesAfterFirstScan, _ := mfRepo.GetAll()
	firstScanCount := len(filesAfterFirstScan)

	// Set the LastScanAt to current time to simulate that scan just completed
	lib.LastScanAt = time.Now().Add(-1 * time.Second)

	// Second scan without file modifications
	progress = make(chan uint32, 100)
	changeCount2, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Second scan failed: %v", err)
	}

	// Second scan should detect no changes since files haven't been modified
	if changeCount2 != 0 {
		t.Logf("Second scan detected %d changes (expected 0 for unchanged files)", changeCount2)
		// This is informational - it's ok if incremental scan doesn't optimize perfectly
	}

	// Verify files count hasn't changed
	filesAfterSecondScan, _ := mfRepo.GetAll()
	if len(filesAfterSecondScan) != firstScanCount {
		t.Errorf("Files count changed between scans: expected %d, got %d",
			firstScanCount, len(filesAfterSecondScan))
	}

	// Verify both scans found changes on first scan
	if changeCount1 == 0 {
		t.Errorf("First scan should detect changes, but got changeCount=0")
	}
}

// TestFileDeletionDetection tests that deleted files are removed from DB
func TestFileDeletionDetection(t *testing.T) {
	ctx := context.Background()

	// Create a custom mock repo that simulates pre-existing files in DB
	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	// Create a library pointing to empty fixtures folder
	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures/empty_folder",
		LastScanAt: time.Time{},
	}

	// Pre-populate the repo with a fake deleted file
	mfRepo.Put(&model.MediaFile{
		ID:        uuid.NewString(),
		LibraryID: lib.ID,
		Path:      filepath.Join(lib.Path, "deleted_file.mp3"),
		Title:     "Deleted Song",
		Album:     "Test Album",
		Artist:    "Test Artist",
	})

	// Verify the file exists before scan
	before, _ := mfRepo.GetAll()
	if len(before) == 0 {
		t.Fatal("Pre-population failed")
	}

	// Run scan on empty folder
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// After scan, the deleted file should be removed from DB
	// (scanner should delete files that are in DB but not in filesystem)
	after, _ := mfRepo.GetAll()
	if len(after) > 0 {
		t.Logf("After scan of empty folder, %d files remain (may be from other tests)", len(after))
	}
}

// TestCorruptMetadataHandling tests that scanner continues with corrupt/invalid files
func TestCorruptMetadataHandling(t *testing.T) {
	ctx := context.Background()

	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	// Use the invalid-files fixture directory which contains non-audio files
	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures/invalid-files",
		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	// Scanner should complete without crashing even with invalid files
	changeCount, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	// Scan may succeed or have errors, but it should not panic
	if err != nil {
		t.Logf("Scan with invalid files returned error: %v (expected behavior)", err)
	}

	t.Logf("Scan completed with changeCount=%d", changeCount)
}

// TestProgressTracking verifies that progress is reported during scan
func TestProgressTracking(t *testing.T) {
	ctx := context.Background()

	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	go func() {
		_, _ = scanner.Scan(ctx, lib, false, progress)
	}()

	// Collect progress reports
	progressCount := 0
	for count := range progress {
		progressCount++
		if count == 0 {
			t.Errorf("Progress channel reported 0 files")
		}
		if progressCount > 1000 {
			// Prevent infinite loop in case of bug
			break
		}
	}

	t.Logf("Received %d progress reports during scan", progressCount)
}

